// // This module checks if the temperature is below 10 degrees Celsius and outputs 1 if it is.
module temperature_shutdown(
    input [3:0] temperature,
    output reg shutdown
);
    always @* begin
        if (temperature > 4'b1010) // 10 in binary
            shutdown = 1;
        else
            shutdown = 0;
    end
endmodule
